+        private void TestSelectorSummary()
+        {
+            LogSelfTest(">>> TESTING SELECTOR SUMMARY");
+
+            var strategyType = typeof(OracleStrategy);
+            var snapshotField = strategyType.GetField("currentSelectorSnapshot", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
+            var summaryMethod = strategyType.GetMethod("GetSelectorSummary", System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
+
+            if (snapshotField == null || summaryMethod == null)
+            {
+                LogSelfTest("Skipping Selector Summary test: Members not found (NinjaTrader Selector implementation not present)");
+                return;
+            }
+
+            var originalSnapshot = snapshotField.GetValue(this);
+
+            try
+            {
+                // Scenario 1: Snapshot is null
+                snapshotField.SetValue(this, null);
+                string result1 = (string)summaryMethod.Invoke(this, null);
+                AssertSelfTest(result1 == "Selector snapshot unavailable", "Scenario 1 (Null Snapshot) failed");
+                LogSelfTest($"Scenario 1 (Null Snapshot): OK - '{result1}'");
+
+                // Scenario 2: Snapshot is valid, Summary is valid
+                var snapshotType = strategyType.GetNestedType("SelectorSnapshot");
+                if (snapshotType == null) 
+                {
+                     LogSelfTest("FAILED: SelectorSnapshot type not found");
+                     return;
+                }
+
+                var snapshot = Activator.CreateInstance(snapshotType);
+                var summaryProp = snapshotType.GetProperty("Summary");
+                if (summaryProp == null)
+                {
+                     LogSelfTest("FAILED: SelectorSnapshot.Summary property not found");
+                     return;
+                }
+
+                summaryProp.SetValue(snapshot, "Test Summary");
+
+                snapshotField.SetValue(this, snapshot);
+                string result2 = (string)summaryMethod.Invoke(this, null);
+                AssertSelfTest(result2 == "Test Summary", "Scenario 2 (Valid Summary) failed");
+                LogSelfTest($"Scenario 2 (Valid Summary): OK - '{result2}'");
+
+                // Scenario 3: Snapshot is valid, Summary is null
+                summaryProp.SetValue(snapshot, null);
+                snapshotField.SetValue(this, snapshot);
+                string result3 = (string)summaryMethod.Invoke(this, null);
+                AssertSelfTest(result3 == string.Empty, "Scenario 3 (Null Summary) failed");
+                LogSelfTest($"Scenario 3 (Null Summary): OK - '{result3}'");
+            }
+            finally
+            {
+                // Restore state
+                snapshotField.SetValue(this, originalSnapshot);
+            }
+        }
+
+        private void AssertSelfTest(bool condition, string message)
+        {
+            if (!condition)
+            {
+                LogSelfTest("FAILED: " + message);
+                throw new Exception("Self-Test Failure: " + message);
+            }
+        }
